def neighbors(i, j):
    if i > 0:
        yield i - 1, j
    if i + 1 < n:
        yield i + 1, j
    if j > 0:
        yield i, j - 1
    if j + 1 < n:
        yield i, j + 1

reachable = {(i, j) for i in range(n) for j in range(n)}
ans = []

for step in range(k):
    best_val = None
    next_reachable = set()

    for i, j in reachable:
        v = grid[i][j]
        if best_val is None or v < best_val:
            best_val = v
            next_reachable = {(i, j)}
        elif v == best_val:
            next_reachable.add((i, j))

    ans.append(best_val)

    if step == k - 1:
        break

    expanded = set()
    for i, j in next_reachable:
        for ni, nj in neighbors(i, j):
            expanded.add((ni, nj))
    reachable = expanded

return ans
